+			(p) => cwd === p.decodedPath || cwd.startsWith(`${p.decodedPath}/`),
+		);
+		groups.push({
+			displayName: extractDisplayName(entry.remote),
+			gitRemote: entry.remote,
+			projects: entry.projects,
+			totalSessions: entry.projects.reduce((s, p) => s + p.sessionCount, 0),
