  1→import {
  2→	afterAll,
  3→	beforeAll,
  4→	beforeEach,
  5→	describe,
  6→	expect,
  7→	test,
  8→} from "bun:test";
  9→import { mkdir, mkdtemp, rm, writeFile } from "node:fs/promises";
 10→import { tmpdir } from "node:os";
 11→import { join } from "node:path";
 12→import type { IngestRequest } from "../lib/types.js";
 13→import { uploadSession } from "../lib/uploader.js";
 14→import {
 15→	signUpTestUser,
 16→	startTestServer,
 17→	type TestServer,
 18→} from "./helpers/bun-server.js";
 19→
 20→let server: TestServer;
 21→let bearerToken: string;
 22→let tempDir: string;
 23→
 24→beforeAll(async () => {
 25→	tempDir = await mkdtemp(join(tmpdir(), "rudel-api-test-"));
 26→	server = await startTestServer();
 27→	bearerToken = await signUpTestUser(server.baseUrl);
 28→}, 60_000);
 29→
 30→afterAll(async () => {
 31→	await server?.stop();
 32→	if (tempDir) {
 33→		await rm(tempDir, { recursive: true, force: true }).catch(() => {});
 34→	}
 35→});
 36→
 37→describe("CLI upload to local API", () => {
 38→	// Bun's test runner may kill the server as a "dangling process" between
 39→	// beforeAll and the first test, or between tests. Restart it if needed.
 40→	beforeEach(async () => {
 41→		await server.ensureAlive();
 42→	});
 43→
 44→	test("uploads a session via uploadSession to the local API", async () => {
 45→		expect(bearerToken).toBeTruthy();
 46→
 47→		const testId = `cli_api_test_${Date.now()}`;
 48→		const request: IngestRequest = {
 49→			sessionId: testId,
 50→			projectPath: "/test/cli-api-upload",
 51→			repository: "test-repo",
 52→			gitBranch: "main",
 53→			gitSha: "abc123",
 54→			tag: "tests",
 55→			content: "cli api integration test content",
 56→			subagents: [{ agentId: "sub-1", content: "subagent content" }],
 57→		};
 58→
 59→		// Retry up to 3 times — ClickHouse can be slow to accept
 60→		// the first request after startup.
 61→		let result = { success: false, error: "not attempted" } as Awaited<
 62→			ReturnType<typeof uploadSession>
 63→		>;
 64→		for (let attempt = 0; attempt < 3; attempt++) {
 65→			result = await uploadSession(request, {
 66→				endpoint: server.rpcUrl,
 67→				token: bearerToken,
 68→			});
 69→			if (result.success) break;
 70→			await Bun.sleep(1000);
 71→		}
 72→
 73→		if (!result.success) {
 74→			throw new Error(`uploadSession failed after 3 attempts: ${result.error}`);
 75→		}
 76→		expect(result.status).toBe(200);
 77→	}, 30_000);
 78→
 79→	test("full CLI upload via subprocess to local API", async () => {
 80→		expect(bearerToken).toBeTruthy();
 81→
 82→		const projectDir = join(tempDir, "cli-e2e-test");
 83→		await mkdir(projectDir, { recursive: true });
 84→
 85→		// Write credentials file using the current server URL (port may have changed)
 86→		const credDir = join(tempDir, "cli-creds");
 87→		await mkdir(credDir, { recursive: true });
 88→		await writeFile(
 89→			join(credDir, "credentials.json"),
 90→			JSON.stringify({ token: bearerToken, apiBaseUrl: server.baseUrl }),
 91→		);
 92→
 93→		const sessionFile = join(projectDir, "e2e-test-session.jsonl");
 94→		await writeFile(
 95→			sessionFile,
 96→			[
 97→				JSON.stringify({
